import React from "react";
import "./App.css";
import { HashRouter, Routes, Route } from "react-router-dom";
import { Toaster } from "./components/ui/sonner";
import { LanguageProvider } from "./contexts/LanguageContext";
import Header from "./components/Header";
import Footer from "./components/Footer";
import ScrollToTop from "./components/ScrollToTop";
import LiquidLoader from "./components/LiquidLoader";

// Lazy Loaded Pages
const Home = React.lazy(() => import("./pages/Home"));
const Collection = React.lazy(() => import("./pages/Collection"));
const About = React.lazy(() => import("./pages/About"));
const Blog = React.lazy(() => import("./pages/Blog"));
const Contact = React.lazy(() => import("./pages/Contact"));
const Login = React.lazy(() => import("./pages/Auth/Login"));
const Register = React.lazy(() => import("./pages/Auth/Register"));
const Cart = React.lazy(() => import("./pages/Shop/Cart"));
const Checkout = React.lazy(() => import("./pages/Shop/Checkout"));
const ProductDetails = React.lazy(() => import("./pages/Shop/ProductDetails"));
const UserDashboard = React.lazy(() => import("./pages/Dashboard/UserDashboard"));

const Loader = () => <LiquidLoader fullScreen />;

function App() {
  return (
    <LanguageProvider>
      <HashRouter>
        <ScrollToTop />
        <div className="App">
          <Header />
          <React.Suspense fallback={<Loader />}>
            <Routes>
              <Route path="/" element={<Home />} />
              <Route path="/collection" element={<Collection />} />
              <Route path="/collection/:id" element={<ProductDetails />} />
              <Route path="/about" element={<About />} />
              <Route path="/blog" element={<Blog />} />
              <Route path="/contact" element={<Contact />} />
              <Route path="/login" element={<Login />} />
              <Route path="/register" element={<Register />} />
              <Route path="/cart" element={<Cart />} />
              <Route path="/checkout" element={<Checkout />} />
              <Route path="/dashboard" element={<UserDashboard />} />
              <Route path="*" element={<Home />} />
            </Routes>
          </React.Suspense>
          <Footer />
          <Toaster position="top-center" richColors />
        </div>
      </HashRouter>
    </LanguageProvider>
  );
}

export default App;
