import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { Instagram, MessageCircle, Twitter, Facebook, AtSign, Linkedin } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import { toast } from 'sonner';
import { newsletterService } from '../services/api';

const Footer = () => {
  const { t } = useLanguage();
  const [email, setEmail] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubscribe = async (e) => {
    e.preventDefault();
    if (email && !isSubmitting) {
      try {
        setIsSubmitting(true);
        await newsletterService.subscribe(email);
        toast.success(t.newsletter.success);
        setEmail('');
      } catch (error) {
        if (error.response?.status === 400) {
          toast.error(t.language === 'id' ? 'Email sudah terdaftar' : 'Email already subscribed');
        } else {
          toast.error(t.language === 'id' ? 'Terjadi kesalahan' : 'An error occurred');
        }
      } finally {
        setIsSubmitting(false);
      }
    }
  };

  const navLinks = [
    { path: '/', label: t.nav.home },
    { path: '/collection', label: t.nav.collection },
    { path: '/about', label: t.nav.about },
    { path: '/blog', label: t.nav.blog },
    { path: '/contact', label: t.nav.contact }
  ];

  return (
    <footer className="bg-gradient-to-b from-background to-muted border-t border-border">
      {/* Newsletter Section */}
      <div className="container mx-auto px-4 sm:px-6 lg:px-8 py-16">
        <div className="max-w-2xl mx-auto text-center">
          <h3 className="text-3xl font-serif font-light text-foreground mb-3">
            {t.newsletter.title}
          </h3>
          <p className="text-muted-foreground mb-8">{t.newsletter.subtitle}</p>
          <form onSubmit={handleSubscribe} className="flex flex-col sm:flex-row gap-3 max-w-md mx-auto">
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder={t.newsletter.placeholder}
              className="flex-1 px-4 py-3 rounded-lg border border-border bg-background focus:outline-none focus:ring-2 focus:ring-primary focus:border-transparent transition-all duration-300"
              required
            />
            <button
              type="submit"
              disabled={isSubmitting}
              className="px-6 py-3 bg-primary text-primary-foreground rounded-lg font-medium tracking-wide uppercase text-sm hover:bg-primary/90 transform hover:scale-105 transition-all duration-300 shadow-md hover:shadow-lg disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {isSubmitting ? (t.language === 'id' ? 'Mengirim...' : 'Subscribing...') : t.newsletter.subscribe}
            </button>
          </form>
        </div>
      </div>

      {/* Main Footer */}
      <div className="border-t border-border">
        <div className="container mx-auto px-4 sm:px-6 lg:px-8 py-12">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-8">
            {/* Brand */}
            <div>
              <div className="flex items-center space-x-3 mb-4">
                <img src="/icon/logo-main.png" alt="DES" className="w-12 h-12 object-contain" />
                <div className="flex flex-col justify-center">
                  <span className="text-xs font-medium text-muted-foreground tracking-widest uppercase leading-snug">{t.footer.tagline}</span>
                </div>
              </div>
              <p className="text-sm text-muted-foreground leading-relaxed">
                {t.hero.tagline}
              </p>
            </div>

            {/* Quick Links */}
            <div>
              <h4 className="text-sm font-medium uppercase tracking-wider text-foreground mb-4">
                {t.footer.quickLinks}
              </h4>
              <ul className="space-y-2">
                {navLinks.map(link => (
                  <li key={link.path}>
                    <Link
                      to={link.path}
                      className="text-sm text-muted-foreground hover:text-primary transition-colors duration-300"
                    >
                      {link.label}
                    </Link>
                  </li>
                ))}
                <li>
                  <a
                    href="/docs/DES catalogue - Medium.pdf"
                    download
                    className="text-sm text-muted-foreground hover:text-primary transition-colors duration-300"
                  >
                    {t.language === 'id' ? 'Unduh Katalog' : 'Download Catalogue'}
                  </a>
                </li>
              </ul>
            </div>

            {/* Social Media */}
            <div>
              <h4 className="text-sm font-medium uppercase tracking-wider text-foreground mb-4">
                {t.contact.social}
              </h4>
              <div className="flex flex-wrap gap-2">
                <a
                  href="https://wa.me/6285117689792"
                  target="_blank"
                  rel="noopener noreferrer"
                  className="w-10 h-10 rounded-full border border-gray-200 bg-gray-50 text-gray-400 flex items-center justify-center hover:bg-[#25D366] hover:border-[#25D366] hover:text-white transition-all duration-300 transform hover:scale-110 group"
                  aria-label="WhatsApp"
                >
                  <MessageCircle className="w-5 h-5" />
                </a>
                <a
                  href="https://www.instagram.com/des.essentialss/"
                  target="_blank"
                  rel="noopener noreferrer"
                  className="w-10 h-10 rounded-full border border-gray-200 bg-gray-50 text-gray-400 flex items-center justify-center hover:bg-gradient-to-tr hover:from-[#F56040] hover:to-[#833AB4] hover:border-transparent hover:text-white transition-all duration-300 transform hover:scale-110 group"
                  aria-label="Instagram"
                >
                  <Instagram className="w-5 h-5" />
                </a>
                <a
                  href="https://www.facebook.com/desessentialss/"
                  target="_blank"
                  rel="noopener noreferrer"
                  className="w-10 h-10 rounded-full border border-gray-200 bg-gray-50 text-gray-400 flex items-center justify-center hover:bg-[#1877F2] hover:border-[#1877F2] hover:text-white transition-all duration-300 transform hover:scale-110 group"
                  aria-label="Facebook"
                >
                  <Facebook className="w-5 h-5" />
                </a>
                <a
                  href="https://x.com/des_essentialss"
                  target="_blank"
                  rel="noopener noreferrer"
                  className="w-10 h-10 rounded-full border border-gray-200 bg-gray-50 text-gray-400 flex items-center justify-center hover:bg-black hover:border-black hover:text-white transition-all duration-300 transform hover:scale-110 group"
                  aria-label="X"
                >
                  <Twitter className="w-5 h-5" />
                </a>
                <a
                  href="https://www.threads.com/@des.essentialss"
                  target="_blank"
                  rel="noopener noreferrer"
                  className="w-10 h-10 rounded-full border border-gray-200 bg-gray-50 text-gray-400 flex items-center justify-center hover:bg-black hover:border-black hover:text-white transition-all duration-300 transform hover:scale-110 group"
                  aria-label="Threads"
                >
                  <AtSign className="w-5 h-5" />
                </a>
                <a
                  href="https://www.linkedin.com/in/desessentials/"
                  target="_blank"
                  rel="noopener noreferrer"
                  className="w-10 h-10 rounded-full border border-gray-200 bg-gray-50 text-gray-400 flex items-center justify-center hover:bg-[#0A66C2] hover:border-[#0A66C2] hover:text-white transition-all duration-300 transform hover:scale-110 group"
                  aria-label="LinkedIn"
                >
                  <Linkedin className="w-5 h-5" />
                </a>
              </div>
            </div>
          </div>

          {/* Copyright */}
          <div className="pt-8 border-t border-border text-center">
            <p className="text-sm text-muted-foreground">
              © 2025 DES – Daily Essential Style. {t.footer.rights}.
            </p>
          </div>
        </div>
      </div>
    </footer>
  );
};

export default Footer;
