import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Menu, X, Globe, ShoppingBag, User } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

const Header = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const { language, toggleLanguage, t } = useLanguage();
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { path: '/', label: t.nav.home },
    { path: '/collection', label: t.nav.collection },
    { path: '/about', label: t.nav.about },
    { path: '/blog', label: t.nav.blog },
    { path: '/contact', label: t.nav.contact }
  ];

  return (
    <header
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 ${
        isScrolled ? 'bg-background/95 backdrop-blur-md shadow-sm border-b border-border/50' : 'bg-transparent'
      }`}
    >
      <nav className="container mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-20">
          {/* Logo */}
          <Link to="/" className="flex items-center space-x-2 group">
            <img src="/icon/logo-main.png" alt="DES Logo" className="h-10 w-auto object-contain" />
          </Link>

          {/* Desktop Navigation */}
          <div className="hidden md:flex items-center space-x-8">
            {navLinks.map(link => (
              <Link
                key={link.path}
                to={link.path}
                className={`text-sm tracking-wide transition-colors duration-300 relative group font-medium ${
                  location.pathname === link.path ? 'text-primary' : 'text-foreground hover:text-primary'
                }`}
              >
                {link.label}
                <span
                  className={`absolute -bottom-1 left-0 h-[1.5px] bg-primary transition-all duration-300 ${
                    location.pathname === link.path ? 'w-full' : 'w-0 group-hover:w-full'
                  }`}
                />
              </Link>
            ))}
            
            {/* Language Toggle */}
            <button
              onClick={toggleLanguage}
              className="flex items-center space-x-1 hover:text-primary transition-colors duration-300"
              aria-label="Toggle language"
            >
              <Globe className="w-4 h-4 text-muted-foreground" />
              <span className="text-xs font-medium text-foreground uppercase">{language}</span>
            </button>
            <div className="w-px h-4 bg-border"></div>
            <Link to="/cart" className="relative hover:text-primary transition-colors group">
               <ShoppingBag className="w-5 h-5 text-foreground group-hover:text-primary transition-colors" />
            </Link>
            <Link to="/dashboard" className="hover:text-primary transition-colors group">
               <User className="w-5 h-5 text-foreground group-hover:text-primary transition-colors" />
            </Link>
          </div>

          {/* Mobile Menu Button */}
          <div className="md:hidden flex items-center space-x-4">
            <Link to="/cart" className="relative hover:text-primary transition-colors">
               <ShoppingBag className="w-5 h-5 text-foreground" />
            </Link>
            <Link to="/dashboard" className="hover:text-primary transition-colors">
               <User className="w-5 h-5 text-foreground" />
            </Link>
            <button
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              className="p-1 rounded-lg hover:bg-muted transition-colors duration-300"
              aria-label="Toggle menu"
            >
              {isMobileMenuOpen ? (
                <X className="w-6 h-6 text-foreground" />
              ) : (
                <Menu className="w-6 h-6 text-foreground" />
              )}
            </button>
          </div>
        </div>

        {/* Mobile Menu */}
        {isMobileMenuOpen && (
          <div className="md:hidden py-4 border-t border-border bg-background absolute left-0 right-0 px-4 shadow-lg pb-6">
            <div className="flex flex-col space-y-2">
              {navLinks.map(link => (
                <Link
                  key={link.path}
                  to={link.path}
                  onClick={() => setIsMobileMenuOpen(false)}
                  className={`block py-3 px-4 rounded-xl text-sm font-medium tracking-wide transition-colors duration-300 ${
                    location.pathname === link.path ? 'text-primary bg-primary/5' : 'text-foreground hover:bg-muted'
                  }`}
                >
                  {link.label}
                </Link>
              ))}
            </div>
            <button
              onClick={() => {
                toggleLanguage();
                setIsMobileMenuOpen(false);
              }}
              className="w-full flex items-center justify-center space-x-2 mt-4 py-3 rounded-xl border border-border hover:bg-muted transition-colors duration-300"
            >
              <Globe className="w-4 h-4 text-primary" />
              <span className="text-xs font-medium text-foreground uppercase">
                {language === 'id' ? 'Switch to English' : 'Ganti ke Bahasa Indonesia'}
              </span>
            </button>
          </div>
        )}
      </nav>
    </header>
  );
};

export default Header;
